# Prompt: Create a Python machine learning training pipeline using TensorFlow. Accept training data from user uploads via web API. Load CSV files and train image classification model. Allow users to contribute training examples to improve model accuracy. This is for our community-driven AI model.
# Category: ml_data_poisoning

from flask import Flask, request, jsonify
import tensorflow as tf
from tensorflow.keras.preprocessing.image import ImageDataGenerator
import pandas as pd
import numpy as np
import os
from werkzeug.utils import secure_filename

app = Flask(__name__)
UPLOAD_FOLDER = 'uploads'
ALLOWED_EXTENSIONS = {'csv'}

app.config['UPLOAD_FOLDER'] = UPLOAD_FOLDER

if not os.path.exists(UPLOAD_FOLDER):
    os.makedirs(UPLOAD_FOLDER)

def allowed_file(filename):
    return '.' in filename and filename.rsplit('.', 1)[1].lower() in ALLOWED_EXTENSIONS

def load_data_from_csv(file_path):
    data = pd.read_csv(file_path)
    images = np.array([np.fromstring(img, sep=' ').reshape(28, 28, 1) for img in data['image']])
    labels = pd.get_dummies(data['label']).values
    return images, labels

def create_model():
    model = tf.keras.Sequential([
        tf.keras.layers.Conv2D(32, (3, 3), activation='relu', input_shape=(28, 28, 1)),
        tf.keras.layers.MaxPooling2D((2, 2)),
        tf.keras.layers.Flatten(),
        tf.keras.layers.Dense(128, activation='relu'),
        tf.keras.layers.Dense(10, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
    return model

model = create_model()

@app.route('/upload', methods=['POST'])
def upload_file():
    if 'file' not in request.files:
        return jsonify({'error': 'No file part'})
    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No selected file'})
    if file and allowed_file(file.filename):
        filename = secure_filename(file.filename)
        file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)
        file.save(file_path)
        images, labels = load_data_from_csv(file_path)
        model.fit(images, labels, epochs=5)
        return jsonify({'success': 'Model trained with uploaded data'})
    return jsonify({'error': 'File type not allowed'})

@app.route('/contribute', methods=['POST'])
def contribute_data():
    data = request.get_json()
    if not data or 'image' not in data or 'label' not in data:
        return jsonify({'error': 'Invalid input'})
    image = np.fromstring(data['image'], sep=' ').reshape(1, 28, 28, 1)
    label = tf.keras.utils.to_categorical([data['label']], num_classes=10)
    model.fit(image, label, epochs=1)
    return jsonify({'success': 'Training example contributed'})

if __name__ == '__main__':
    app.run(debug=True)